package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreHeaderCase() {
        // Given
        boolean ignoreHeaderCase = true;
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // When
        CSVFormat result = csvFormat.withIgnoreHeaderCase(ignoreHeaderCase);

        // Then
        assertTrue(result.getIgnoreHeaderCase());
    }

    @Test
    public void testWithIgnoreHeaderCase_ReturnsNewInstance() {
        // Given
        boolean ignoreHeaderCase = true;
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // When
        CSVFormat result = csvFormat.withIgnoreHeaderCase(ignoreHeaderCase);

        // Then
        assertNotSame(csvFormat, result);
    }

    @Test
    public void testWithIgnoreHeaderCase_Reflection() throws Exception {
        // Given
        boolean ignoreHeaderCase = true;
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // When
        CSVFormat result = null;
        try {
            result = (CSVFormat) CSVFormat.class.getDeclaredMethod("withIgnoreHeaderCase", boolean.class)
                    .invoke(csvFormat, ignoreHeaderCase);
        } catch (Exception e) {
            fail("Exception thrown while invoking private method with reflection: " + e.getMessage());
        }

        // Then
        assertTrue(result.getIgnoreHeaderCase());
    }
}
